// Efficient single std::format invocation
#include <format>
#include <string>

void printUserInfo(const std::string& name, int age, const std::string& city) {
    // Compliant: single std::format call with proper format string
    std::string message = std::format("Name: {}, Age: {}, City: {}", name, age, city);

    // Compliant: single format call for greeting
    std::string greeting = std::format("Hello {}!", name);

    // Compliant: complex formatting in one call
    std::string report = std::format("User Report:\n"
                                    "  Name: {}\n"
                                    "  Age: {} years old\n"
                                    "  Location: {}\n", 
                                    name, age, city);
}
